    const mandatoryEdges: number[][] = [];
    const optionalEdges: number[][] = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mandatoryEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
